import { ObdDataPoint, ObdMetric, TripStats } from '../types';

interface PidDefinition {
  name: string;
  unit: string;
  formula: (bytes: number[]) => number;
}

export interface ObdSegment {
  id: number;
  startTime: number;
  endTime: number;
  startLabel: string;
  endLabel: string;
  dataPoints: ObdDataPoint[];
}

const PID_MAP: Record<string, PidDefinition> = {
  '04': { name: '엔진 부하', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '05': { name: '냉각수 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '06': { name: '단기 연료 보정', unit: '%', formula: (v) => (v[0] - 128) * 100 / 128 },
  '07': { name: '장기 연료 보정', unit: '%', formula: (v) => (v[0] - 128) * 100 / 128 },
  '0C': { name: '엔진 회전수', unit: 'rpm', formula: (v) => (v[0] * 256 + v[1]) / 4 },
  '0D': { name: '주행 속도', unit: 'km/h', formula: (v) => v[0] },
  '0E': { name: '점화 시기', unit: '°', formula: (v) => v[0] / 2 - 64 },
  '0F': { name: '흡기 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '10': { name: '흡입 공기량', unit: 'g/s', formula: (v) => (v[0] * 256 + v[1]) / 100 },
  '11': { name: '스로틀 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '2F': { name: '연료 잔량', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '42': { name: '제어 모듈 전압', unit: 'V', formula: (v) => (v[0] * 256 + v[1]) / 1000 },
  '49': { name: '가속 페달 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '5C': { name: '엔진 오일 온도', unit: '°C', formula: (v) => v[0] - 40 },
};

/**
 * Updated Regex to support:
 * 1. iOS Headers (7DF, 010C >)
 * 2. Mixed responses (41 0C 0A 12 or NODATA)
 * 3. Optional delay or schedule keywords
 */
const OBD_LINE_REGEX = /^\[(?:([\d-]+\s)?(\d{2}:\d{2}:\d{2}[:\.]\d{3}))\]\s*.*?(01\s?[0-9A-F]{2})\s*[:|>]\s*([^,\[]+?)(?:\s*,\s*(?:delay|schedule)\s*[:=]\s*(\w+))?/i;

export const parseObdLine = (line: string): ObdDataPoint | null => {
  const match = line.match(OBD_LINE_REGEX);
  if (!match) return null;

  const fullDatePart = match[1] || ""; 
  const timePart = match[2];           
  const fullPid = match[3].replace(/\s/g, '').toUpperCase(); 
  const rawData = match[4].trim().toUpperCase(); 
  const delayStr = match[5];
  const pid = fullPid.substring(2);

  // NODATA or ERROR filtering
  if (rawData.includes('NODATA') || rawData.includes('ERROR') || rawData.includes('STOPPED')) return null;

  const serviceMarker = '41' + pid;
  const serviceIdx = rawData.indexOf(serviceMarker);
  if (serviceIdx === -1) return null;

  const dataStartIdx = serviceIdx + serviceMarker.length;
  const dataHex = rawData.substring(dataStartIdx).replace(/[\s/]/g, '');
  if (!dataHex) return null;

  const bytes: number[] = [];
  for (let i = 0; i < dataHex.length; i += 2) {
    const byte = parseInt(dataHex.substring(i, i + 2), 16);
    if (!isNaN(byte)) bytes.push(byte);
  }

  const def = PID_MAP[pid];
  if (!def || bytes.length === 0) return null;

  try {
    const today = new Date().toISOString().split('T')[0];
    const timestampStr = fullDatePart 
      ? (fullDatePart + timePart).replace(' ', 'T').replace(/:(\d{3})$/, '.$1')
      : `${today}T${timePart.replace(/:(\d{3})$/, '.$1')}`;

    const timestamp = new Date(timestampStr);
    const value = def.formula(bytes);

    // Numeric delay parsing (default to 0 if "setProtocol" etc.)
    const delay = delayStr && !isNaN(parseInt(delayStr)) ? parseInt(delayStr) : 0;

    return {
      timestamp,
      timeStr: timePart,
      unix: timestamp.getTime(),
      pid,
      name: def.name,
      value: Number(value.toFixed(2)),
      unit: def.unit,
      delay,
      ecuId: rawData.substring(0, serviceIdx).substring(0, 3).trim() || '7E8'
    };
  } catch (e) {
    return null;
  }
};

export const calculateTripStats = (series: ObdDataPoint[]): TripStats => {
  if (series.length < 2) {
    return {
      totalDistanceKm: 0, averageSpeedKmh: 0, maxRpm: 0, maxSpeedKmh: 0,
      idleDurationMs: 0, durationMs: 0, hardBrakingCount: 0, rapidAccelerationCount: 0
    };
  }

  const speedSeries = series.filter(s => s.pid === '0D');
  const rpmSeries = series.filter(s => s.pid === '0C');
  const mafSeries = series.filter(s => s.pid === '10');

  let totalDistance = 0;
  let idleMs = 0;
  let hardBraking = 0;
  let rapidAccel = 0;

  for (let i = 1; i < speedSeries.length; i++) {
    const prev = speedSeries[i-1];
    const curr = speedSeries[i];
    const dtSeconds = (curr.unix - prev.unix) / 1000;

    if (dtSeconds > 0 && dtSeconds < 10) {
      totalDistance += (curr.value * (dtSeconds / 3600));
      const accel = (curr.value - prev.value) / dtSeconds;
      if (accel > 8) rapidAccel++;
      if (accel < -12) hardBraking++;
    }
  }

  if (rpmSeries.length > 0) {
    for (let i = 1; i < rpmSeries.length; i++) {
      const rpm = rpmSeries[i];
      const correspondingSpeed = speedSeries.find(s => Math.abs(s.unix - rpm.unix) < 2000)?.value || 0;
      if (rpm.value > 500 && correspondingSpeed < 1) {
        idleMs += (rpm.unix - rpmSeries[i-1].unix);
      }
    }
  }

  const duration = series[series.length - 1].unix - series[0].unix;
  const avgSpeed = totalDistance / (duration / 3600000);

  let fuelEconomy = undefined;
  if (mafSeries.length > 0 && totalDistance > 0.1) {
    let totalMafGrams = 0;
    for (let i = 1; i < mafSeries.length; i++) {
        const dt = (mafSeries[i].unix - mafSeries[i-1].unix) / 1000;
        totalMafGrams += (mafSeries[i].value * dt);
    }
    const totalFuelGrams = totalMafGrams / 14.7;
    const totalFuelLiters = totalFuelGrams / 720;
    fuelEconomy = totalDistance / totalFuelLiters;
  }

  return {
    totalDistanceKm: Number(totalDistance.toFixed(2)),
    averageSpeedKmh: Number(avgSpeed.toFixed(1)),
    maxRpm: Math.max(...rpmSeries.map(s => s.value), 0),
    maxSpeedKmh: Math.max(...speedSeries.map(s => s.value), 0),
    idleDurationMs: idleMs,
    durationMs: duration,
    hardBrakingCount: hardBraking,
    rapidAccelerationCount: rapidAccel,
    estimatedFuelEconomy: fuelEconomy ? Number(fuelEconomy.toFixed(1)) : undefined
  };
};

export const detectSegments = (series: ObdDataPoint[]): ObdSegment[] => {
  if (series.length === 0) return [];
  const segments: ObdSegment[] = [];
  let currentPoints: ObdDataPoint[] = [series[0]];
  const GAP_THRESHOLD_MS = 60000; 
  for (let i = 1; i < series.length; i++) {
    const prev = series[i - 1];
    const curr = series[i];
    if (curr.unix - prev.unix > GAP_THRESHOLD_MS) {
      segments.push({
        id: segments.length + 1,
        startTime: currentPoints[0].unix,
        endTime: currentPoints[currentPoints.length - 1].unix,
        startLabel: currentPoints[0].timeStr,
        endLabel: currentPoints[currentPoints.length - 1].timeStr,
        dataPoints: currentPoints
      });
      currentPoints = [curr];
    } else {
      currentPoints.push(curr);
    }
  }
  if (currentPoints.length > 0) {
    segments.push({
      id: segments.length + 1,
      startTime: currentPoints[0].unix,
      endTime: currentPoints[currentPoints.length - 1].unix,
      startLabel: currentPoints[0].timeStr,
      endLabel: currentPoints[currentPoints.length - 1].timeStr,
      dataPoints: currentPoints
    });
  }
  return segments;
};

export const aggregateMetrics = (series: ObdDataPoint[]): Record<string, ObdMetric> => {
  const metrics: Record<string, ObdMetric> = {};
  Object.entries(PID_MAP).forEach(([id, def]) => {
    const pidSeries = series.filter(s => s.pid === id);
    metrics[id] = {
      id,
      name: def.name,
      unit: def.unit,
      currentValue: pidSeries.length > 0 ? pidSeries[pidSeries.length - 1].value : 0,
      history: pidSeries.map(s => ({ t: s.unix, v: s.value })),
      isAvailable: pidSeries.length > 0
    };
  });
  return metrics;
};

import { LogEntry, LogCategory, SessionMetadata, ParsedData, BillingEntry, LifecycleEvent, StorageStatus, PurchasedProfile } from '../types';
import { parseObdLine, aggregateMetrics, calculateTripStats } from './obdParser';

const REGEX_GUIDE_TIMESTAMP = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s*:\s*(.*)/;
const REGEX_GPA_ID = /GPA\.\d{4}-\d{4}-\d{4}-\d{4}/g;

const parseLogDate = (timestampStr: string): Date => {
  try {
    const isoStr = timestampStr.replace(' ', 'T').replace(/:(\d{3})$/, '.$1');
    return new Date(isoStr);
  } catch {
    return new Date();
  }
};

const isValidValue = (v: any): boolean => {
  if (v === null || v === undefined) return false;
  const s = String(v).trim();
  const lower = s.toLowerCase();
  return (
    s !== "" && 
    lower !== "null" && 
    lower !== "none" && 
    lower !== "undefined" && 
    lower !== "알 수 없음" &&
    lower !== "알수없음" &&
    lower !== "unknown"
  );
};

const parseProfiles = (message: string): PurchasedProfile[] => {
  const profiles: PurchasedProfile[] = [];
  const match = message.match(/userPurchasedProfiles\s*:\s*\[(.*?)\]/s);
  if (!match) return [];
  const profilesContent = match[1];
  const profileBlocks = profilesContent.split(/Profile\(/).filter(p => p.trim());
  profileBlocks.forEach(block => {
    try {
      const getVal = (key: string) => {
        const regex = new RegExp(`${key}=(?:Model\\{)?(?:['"]?)([^,'"}]+)(?:['"]?)(?:\\})?`, 'i');
        return block.match(regex)?.[1] || 'Unknown';
      };
      const modelKo = block.match(/modelName_ko='([^']+)'/)?.[1];
      const modelEn = block.match(/modelName_en='([^']+)'/)?.[1];
      profiles.push({
        id: getVal('id'),
        region: getVal('regionName'),
        modelName: modelKo || modelEn || 'Unknown Model',
        year: getVal('modelYear'),
        engine: getVal('engineType'),
        isMobdPlus: getVal('isMobdPlus') === 'true',
        updateTime: getVal('updateTime')
      });
    } catch (e) {
      console.warn("Failed to parse profile block", block);
    }
  });
  return profiles;
};

export const parseLogFile = (content: string, fileName: string, billingContent: string = ''): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const billingLogs: BillingEntry[] = [];
  const purchasedProfiles: PurchasedProfile[] = [];
  const orderIdSet = new Set<string>();
  const obdSeries: any[] = [];

  const metadata: SessionMetadata = {
    fileName, model: '알 수 없음', userOS: '알 수 없음', appVersion: '알 수 없음', carName: '알 수 없음', userId: '알 수 없음',
    logCount: 0, startTime: null, endTime: null, deviceInfo: {}, protocolInfo: {}, obd2Info: {}, userInfo: {}, carInfo: {}, settingInfo: {}
  };

  const storageInfo: StorageStatus = { availableBytes: 'Unknown', settingsSize: 'Unknown', exists: false, readable: false, writable: false };
  let currentSection = 'UNKNOWN';
  let lastLogEntry: LogEntry | null = null;
  const allLines = [...lines, ...billingContent.split(/\r?\n/)];

  // Helper to update metadata fields with validation
  const updateMetadataField = (field: string, value: string, subMap?: string) => {
    if (!isValidValue(value)) return;

    if (subMap) {
      const map = (metadata as any)[subMap];
      if (map && (!isValidValue(map[field]) || map[field] === '알 수 없음')) {
        map[field] = value;
      }
    } else {
      const current = (metadata as any)[field];
      if (!isValidValue(current) || current === '알 수 없음') {
        (metadata as any)[field] = value;
      }
    }
  };

  // 주요 식별자 리스트 (어떤 섹션에서든 발견되면 userInfo에 저장)
  const USER_KEYS = ['userId', 'userKey', 'userType', 'userEmail', 'companyCode'];

  allLines.forEach((line) => {
    if (!line.trim()) return;

    // 1. 섹션 헤더 처리
    const sectionMatch = line.match(SECTION_HEADER);
    if (sectionMatch) {
      currentSection = sectionMatch[1].toUpperCase().replace(/\sINFO/g, '');
      return;
    }

    // 2. Key-Value 파싱
    const kvMatch = line.match(KEY_VALUE_PAIR);
    if (kvMatch && !line.trim().startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();

      // 전역 매핑 시도
      if (k === 'model') updateMetadataField('model', v);
      if (k === 'carName') updateMetadataField('carName', v);
      if (k === 'userOS') updateMetadataField('userOS', v);
      if (k === 'version' || k === 'App version') updateMetadataField('appVersion', v);
      if (k === 'countryCode' || k === 'country') updateMetadataField('countryCode', v);
      if (k === 'protocol' || k === 'AT DPN') updateMetadataField('protocol', v);

      // 사용자 정보는 어떤 위치에서든 캡처
      if (USER_KEYS.includes(k)) {
        updateMetadataField(k, v, 'userInfo');
        if (k === 'userId' || k === 'userKey') updateMetadataField('userId', v);
      }

      // 현재 섹션에 기반한 상세 정보 업데이트
      const subMapName = `${currentSection.toLowerCase()}Info`;
      if ((metadata as any)[subMapName]) {
        updateMetadataField(k, v, subMapName);
      }
      return;
    }

    // 3. 로그 데이터 파싱 (타임스탬프 기반)
    const tsMatch = line.match(REGEX_GUIDE_TIMESTAMP);
    if (tsMatch) {
      const rawTimestamp = tsMatch[1];
      const timestamp = parseLogDate(rawTimestamp);
      const message = tsMatch[2];

      const isBilling = /purchase|signature|receipt|verifyReceipt|available storage|Setting\.xml|userPurchasedProfiles/i.test(message) || fileName.includes('billing');
      const category = isBilling ? LogCategory.BILLING : (message.includes('01 ') ? LogCategory.OBD : LogCategory.INFO);

      const gpaMatches = message.match(REGEX_GPA_ID);
      if (gpaMatches) gpaMatches.forEach(id => orderIdSet.add(id));

      if (message.includes('userPurchasedProfiles')) {
        const found = parseProfiles(message);
        if (found.length > 0) purchasedProfiles.push(...found.filter(f => !purchasedProfiles.some(p => p.id === f.id)));
      }

      const logEntry: LogEntry = {
        id: logs.length, timestamp, rawTimestamp, message,
        category, isError: /fail|exception|error|unable/i.test(message),
        originalLine: line
      };
      logs.push(logEntry);
      lastLogEntry = logEntry;

      // 라이프사이클 이벤트
      const isScreen = message.includes('Move to screen') || message.includes('setScreen') || message.includes('onStart') || message.includes('onResume');
      const isConnection = message.includes('Bluetooth') || message.includes('connectionSuccess') || message.includes('AT ') || message.includes('ELM');
      if (isScreen || isConnection) {
        lifecycleEvents.push({
          id: lifecycleEvents.length, timestamp, rawTimestamp,
          type: isScreen ? 'SCREEN' : 'CONNECTION',
          message: message.trim(), details: line
        });
      }

      if (isBilling) {
        if (message.includes('Available storage')) storageInfo.availableBytes = message.split(':')[1]?.trim();
        if (message.includes('Setting.xml size')) storageInfo.settingsSize = message.split(':')[1]?.trim();
        if (message.includes('Setting.xml does not exist')) storageInfo.exists = false;
        if (message.includes('Setting.xml size')) storageInfo.exists = true;
      }

      const obdPoint = parseObdLine(line);
      if (obdPoint) obdSeries.push(obdPoint);
    } else if (lastLogEntry) {
      // 타임스탬프가 없는 줄은 이전 로그에 병합 (Stacktrace 등)
      lastLogEntry.message += '\n' + line;

      // 병합된 줄에서도 Key-Value 패턴이 보이면 메타데이터 업데이트 시도
      const innerKv = line.match(KEY_VALUE_PAIR);
      if (innerKv) {
        const k = innerKv[1].trim();
        const v = innerKv[2].trim();
        if (USER_KEYS.includes(k)) updateMetadataField(k, v, 'userInfo');
      }
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  return { 
    metadata, logs, lifecycleEvents, billingLogs, billingFlows: [], 
    purchasedProfiles, orderIds: Array.from(orderIdSet),
    storageInfo, diagnosis: { status: 'SUCCESS', summary: '정상', issues: [], csType: 'NONE' }, 
    fileList: [], obdSeries, metrics: aggregateMetrics(obdSeries),
    tripStats: calculateTripStats(obdSeries)
  };
};

