        {dtc.code}
      </div>
      <div>
        <div className="flex items-center gap-2">
          <span className="text-xs font-bold text-slate-800 uppercase">{dtc.type} Code</span>
          <span className={`text-[10px] px-1.5 py-0.5 rounded font-black uppercase ${
            dtc.status === 'Confirmed' ? 'bg-red-100 text-red-700' :
            dtc.status === 'Pending' ? 'bg-amber-100 text-amber-700' :
            'bg-slate-100 text-slate-500'
          }`}>
            {dtc.status}
          </span>
        </div>
        <p className="text-[11px] text-slate-500 font-mono">Raw: {dtc.rawHex}</p>
      </div>
    </div>
    <button onClick={() => window.open(`https://www.google.com/search?q=OBD2+DTC+${dtc.code}`, '_blank')} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">
      <Search className="w-4 h-4" />
    </button>
  </div>
);

const MetricCard: React.FC<any> = ({ name, value, unit, isAvailable, isSelected, icon, onClick }) => (
  <div 
    onClick={isAvailable ? onClick : undefined}
    className={`bg-white p-4 rounded-xl border-2 transition-all hover:shadow-md flex items-center justify-between group ${
      isSelected ? 'border-indigo-500 shadow-indigo-100 ring-2 ring-indigo-50' : 'border-slate-200'
    } ${isAvailable ? 'cursor-pointer' : 'opacity-40 grayscale cursor-not-allowed'}`}
  >
    <div className="flex items-center gap-4">
      <div className={`p-2.5 rounded-lg transition-colors ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400 group-hover:bg-slate-100'}`}>
        {icon}
      </div>
      <div className="flex flex-col">
        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">{name}</span>
        <div className="flex items-baseline gap-1">
          <span className="text-xl font-black text-slate-800">{isAvailable ? value : '--'}</span>
          <span className="text-[10px] font-bold text-slate-400 uppercase">{unit}</span>
        </div>
      </div>
    </div>
  </div>
);

export const ObdDashboard: React.FC<ObdDashboardProps> = ({ series, metrics, detectedDtcs = [] }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [currentTime, setCurrentTime] = useState(0); 
  const [selectedPids, setSelectedPids] = useState<Set<string>>(new Set(['0C', '0D']));
  const [activeSegmentId, setActiveSegmentId] = useState<number>(0); 
  const [isFollowMode, setIsFollowMode] = useState(true);
  const [viewWindowMs, setViewWindowMs] = useState(120000);

  const requestRef = useRef<number>();
  const lastUpdateRef = useRef<number>();

  const segments = useMemo(() => detectSegments(series), [series]);

  const activeSeries = useMemo(() => {
    if (activeSegmentId === 0) return series;
    return segments.find(s => s.id === activeSegmentId)?.dataPoints || [];
  }, [activeSegmentId, series, segments]);

  const tripStats = useMemo(() => calculateTripStats(activeSeries), [activeSeries]);

  const startTime = activeSeries[0]?.unix || 0;
  const endTime = activeSeries[activeSeries.length - 1]?.unix || 0;
  const totalDuration = endTime - startTime;

  const animate = (time: number) => {
    if (lastUpdateRef.current !== undefined) {
      const deltaTime = time - lastUpdateRef.current;
      setCurrentTime(prev => {
        const next = prev + deltaTime * playbackSpeed;
        if (next >= totalDuration) {
          setIsPlaying(false);
          return totalDuration;
        }
        return next;
      });
    }
    lastUpdateRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (isPlaying) {
      requestRef.current = requestAnimationFrame(animate);
    } else {
      lastUpdateRef.current = undefined;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, playbackSpeed]);

  const currentValues = useMemo(() => {
    const currentUnix = startTime + currentTime;
    const latest: Record<string, number> = {};
    activeSeries.forEach((p) => {
      if (p.unix <= currentUnix) {
        latest[p.pid] = p.value;
      }
    });
    return latest;
  }, [currentTime, activeSeries, startTime]);

  const chartData = useMemo(() => {
    const dataBySec: Record<number, any> = {};
    activeSeries.forEach((p) => {
      const sec = Math.floor((p.unix - startTime) / 1000) * 1000;
      if (!dataBySec[sec]) {
        dataBySec[sec] = { t: sec, timeLabel: formatSimTime(sec) };
      }
      dataBySec[sec][p.pid] = p.value;
    });
    const sorted = Object.values(dataBySec).sort((a: any, b: any) => a.t - b.t);
    if (!isFollowMode) return sorted;
    const halfWindow = viewWindowMs / 2;
    const minT = Math.max(0, currentTime - halfWindow);
    const maxT = minT + viewWindowMs;
    return sorted.filter((d: any) => d.t >= minT && d.t <= maxT);
  }, [activeSeries, startTime, isFollowMode, currentTime, viewWindowMs]);

  const togglePid = (pid: string) => {
    setSelectedPids(prev => {
      const next = new Set(prev);
      if (next.has(pid)) next.delete(pid);
      else next.add(pid);
      return next;
    });
  };

  function formatSimTime(ms: number) {
    const totalSeconds = Math.floor(ms / 1000);
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }

  const getIcon = (pid: string) => {
    switch(pid) {
      case '0C': return <Activity className="w-5 h-5" />;
      case '0D': return <Zap className="w-5 h-5" />;
      case '05': 
      case '0F': 
      case '46':
      case '5C': return <Thermometer className="w-5 h-5" />;
      case '04': 
      case '43': return <Gauge className="w-5 h-5" />;
      case '0A':
      case '0B':
      case '23':
      case '33': return <CloudRain className="w-5 h-5" />;
      case '42': return <Battery className="w-5 h-5" />;
      case '1F': return <Timer className="w-5 h-5" />;
      case '2F':
      case '52': return <Fuel className="w-5 h-5" />;
      default: return <Wind className="w-5 h-5" />;
    }
  };

  const colors = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#3b82f6', '#8b5cf6', '#ec4899', '#14b8a6'];

  return (
    <div className="space-y-6 pb-12 animate-in fade-in duration-500">

      {/* 주행 요약 통계 */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-7 gap-4">
        <StatCard label="주행 거리" value={tripStats.totalDistanceKm} unit="km" icon={Navigation} color="bg-blue-100 text-blue-600" />
        <StatCard label="평균 속도" value={tripStats.averageSpeedKmh} unit="km/h" icon={TrendingUp} color="bg-emerald-100 text-emerald-600" />
        <StatCard label="최고 RPM" value={tripStats.maxRpm} unit="rpm" icon={Activity} color="bg-amber-100 text-amber-600" />
        <StatCard label="공회전 시간" value={formatSimTime(tripStats.idleDurationMs)} unit="" icon={Clock} color="bg-slate-100 text-slate-600" />
        <StatCard label="급감속/가속" value={`${tripStats.hardBrakingCount}/${tripStats.rapidAccelerationCount}`} unit="회" icon={AlertTriangle} color="bg-red-100 text-red-600" />
        <StatCard label="고장 코드" value={detectedDtcs.length} unit="개" icon={Stethoscope} color={detectedDtcs.length > 0 ? "bg-red-600 text-white animate-pulse" : "bg-green-100 text-green-600"} />
        <StatCard label="추정 연비" value={tripStats.estimatedFuelEconomy || '--'} unit="km/L" icon={Droplets} color="bg-indigo-100 text-indigo-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Diagnostic Section */}
        <div className="lg:col-span-1 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
             <div className="flex items-center justify-between mb-4">
               <h3 className="font-bold text-slate-900 flex items-center gap-2">
                 <Stethoscope className="w-5 h-5 text-indigo-600" /> 차량 진단 결과
               </h3>
               {detectedDtcs.length > 0 && <ShieldAlert className="w-5 h-5 text-red-500" />}
             </div>

             <div className="space-y-3 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                {detectedDtcs.length > 0 ? (
                  detectedDtcs.map((dtc, idx) => (
                    <DtcRow key={`${dtc.code}-${idx}`} dtc={dtc} />
                  ))
                ) : (
                  <div className="py-12 text-center flex flex-col items-center gap-3">
                    <div className="w-12 h-12 bg-green-50 rounded-full flex items-center justify-center">
                       <Zap className="w-6 h-6 text-green-500" />
                    </div>
                    <p className="text-sm font-bold text-slate-800">발견된 고장 코드가 없습니다.</p>
                    <p className="text-[10px] text-slate-400">ECU가 모든 시스템을 정상으로 보고하고 있습니다.</p>
                  </div>
                )}
             </div>
          </div>

          {/* Trip Selector */}
          <div className="bg-slate-900 p-6 rounded-2xl shadow-xl border border-slate-800">
             <h3 className="text-white font-bold text-sm mb-4 flex items-center gap-2 uppercase tracking-widest opacity-50">
               <Map className="w-4 h-4" /> Trip Segments
             </h3>
             <div className="space-y-2">
                <button onClick={() => { setActiveSegmentId(0); setCurrentTime(0); }} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-sm font-bold transition-all border ${activeSegmentId === 0 ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-slate-800 text-slate-400 border-slate-700 hover:bg-slate-750'}`}>
                  전체 주행 기록 <span>{formatSimTime(totalDuration)}</span>
                </button>
                {segments.map(seg => (
                  <button key={seg.id} onClick={() => { setActiveSegmentId(seg.id); setCurrentTime(0); }} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-sm font-bold transition-all border ${activeSegmentId === seg.id ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-slate-800 text-slate-400 border-slate-700 hover:bg-slate-750'}`}>
                    Trip {seg.id} <span className="text-[10px] opacity-60">{seg.startLabel} ~ {seg.endLabel}</span>
                  </button>
                ))}
             </div>
          </div>
        </div>

        {/* Playback & Main Chart */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-slate-900 p-6 rounded-2xl shadow-xl border border-slate-800 flex flex-col gap-6">
            <div className="flex flex-col md:flex-row items-center gap-6">
              <div className="flex items-center gap-3">
                <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 flex items-center justify-center bg-indigo-600 hover:bg-indigo-500 text-white rounded-full transition-all shadow-lg">
                  {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                </button>
                <button onClick={() => { setIsPlaying(false); setCurrentTime(0); }} className="w-10 h-10 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-full transition-all">
                  <RotateCcw className="w-5 h-5" />
                </button>
              </div>
              <div className="flex-1 w-full space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                  <span>재생 위치: {formatSimTime(currentTime)}</span>
                  <span>트립 시간: {formatSimTime(totalDuration)}</span>
                </div>
                <input type="range" min={0} max={totalDuration} value={currentTime} onChange={(e) => setCurrentTime(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500" />
              </div>
              <div className="flex items-center bg-slate-800 p-1 rounded-lg">
                {[1, 4, 16, 32].map(speed => (
                  <button key={speed} onClick={() => setPlaybackSpeed(speed)} className={`px-3 py-1 rounded text-xs font-bold transition-all ${playbackSpeed === speed ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}>
                    {speed}x
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {['0C', '0D', '04', '05'].map(pid => {
                const m = metrics[pid];
                if (!m || !m.isAvailable) return null;
                return (
                  <div key={pid} className="bg-slate-800 p-3 rounded-xl border border-slate-700 flex flex-col">
                    <span className="text-[10px] font-bold text-slate-500 uppercase">{m.name}</span>
                    <span className="text-lg font-black text-white">{currentValues[pid] !== undefined ? currentValues[pid] : '--'} <span className="text-[10px] opacity-40">{m.unit}</span></span>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
              <div className="flex items-center gap-4">
                <h3 className="font-bold text-slate-900 flex items-center gap-2 shrink-0">
                  <Activity className="w-5 h-5 text-indigo-600" /> 주행 데이터 정밀 분석
                </h3>
                <div className="flex items-center bg-slate-100 p-1 rounded-lg border border-slate-200">
                  <button onClick={() => setIsFollowMode(!isFollowMode)} className={`flex items-center gap-1.5 px-3 py-1 rounded text-xs font-bold transition-all ${isFollowMode ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>
                    <Target className="w-3.5 h-3.5" /> 추적 모드
                  </button>
                  <div className="w-px h-4 bg-slate-200 mx-1" />
                  <select className="bg-transparent border-none text-[11px] font-bold text-slate-500 focus:ring-0 outline-none cursor-pointer" value={viewWindowMs} onChange={(e) => setViewWindowMs(Number(e.target.value))}>
                    <option value={30000}>30초 뷰</option>
                    <option value={60000}>1분 뷰</option>
                    <option value={120000}>2분 뷰</option>
                    <option value={300000}>5분 뷰</option>
                  </select>
                </div>
              </div>
              <div className="flex flex-wrap gap-2">
                {[...selectedPids].map((pid: string, idx: number) => (
                  <div key={pid} className="flex items-center gap-1.5 px-2 py-1 bg-slate-50 border border-slate-200 rounded text-[10px] font-bold text-slate-600 shadow-sm">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: colors[idx % colors.length] }} />
                    {metrics[pid]?.name}
                  </div>
                ))}
              </div>
            </div>
            <div className="h-[350px]">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 10, right: 30, left: 20, bottom: 10 }}>
                  <defs>
                    {colors.map((color, idx) => (
                      <linearGradient key={idx} id={`color${idx}`} x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor={color} stopOpacity={0.3}/>
                        <stop offset="95%" stopColor={color} stopOpacity={0}/>
                      </linearGradient>
                    ))}
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="t" fontSize={10} tickFormatter={(val) => formatSimTime(val)} axisLine={false} tickLine={false} />
                  <YAxis fontSize={10} axisLine={false} tickLine={false} />
                  <Tooltip labelFormatter={(val) => `Time: ${formatSimTime(Number(val))}`} contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff', fontSize: '12px' }} itemStyle={{ padding: '2px 0' }} />
                  <Legend verticalAlign="top" height={36}/>
                  {[...selectedPids].map((pid: string, idx: number) => (
                    <Area key={pid} type="monotone" dataKey={pid} name={metrics[pid]?.name} stroke={colors[idx % colors.length]} fillOpacity={1} fill={`url(#color${idx % colors.length})`} strokeWidth={2} dot={false} isAnimationActive={false} />
                  ))}
                  <ReferenceLine x={currentTime} stroke="#ef4444" strokeWidth={2} strokeDasharray="5 5" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {(Object.values(metrics) as ObdMetric[]).filter(m => m.isAvailable).map((m: ObdMetric) => (
          <MetricCard 
            key={m.id}
            name={m.name}
            value={currentValues[m.id] !== undefined ? currentValues[m.id] : '--'}
            unit={m.unit}
            isAvailable={m.isAvailable}
            isSelected={selectedPids.has(m.id)}
            icon={getIcon(m.id)}
            onClick={() => togglePid(m.id)}
          />
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ParsedData } from '../types';
import { LogTable } from './LogTable';
import { EventTimeline } from './EventTimeline';
import { SessionInfo } from './SessionInfo';
import { BillingList } from './BillingList';
import { ObdDashboard } from './ObdDashboard';
import { 
  FileText, 
  BarChart2, History, CreditCard, 
  Gauge, Settings
} from 'lucide-react';

interface DashboardProps {
  data: ParsedData;
  onReset: () => void;
  onFileSelect: (fileName: string) => void;
}

type TabType = 'OVERVIEW' | 'LOGS' | 'TIMELINE' | 'BILLING' | 'DETAILS';

export const Dashboard: React.FC<DashboardProps> = ({ data, onReset, onFileSelect }) => {
  const { metadata, logs, lifecycleEvents, billingLogs, purchasedProfiles, orderIds, fileList, obdSeries, metrics, diagnosis } = data;
  const [activeTab, setActiveTab] = useState<TabType>('OVERVIEW');

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      {/* 헤더 */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
        <div className="flex-1">
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2 mb-2">
            <span className="bg-indigo-600 text-white p-1 rounded text-lg">INF</span> Infocar 로그 분석기
          </h1>

          <div className="flex items-center gap-3">
             <div className="relative group">
                <div className="flex items-center gap-2 bg-slate-100 hover:bg-slate-200 transition-colors px-3 py-1.5 rounded-md cursor-pointer border border-slate-200">
                    <FileText className="w-4 h-4 text-slate-600" />
                    <select 
                        className="bg-transparent border-none text-sm font-medium text-slate-700 focus:ring-0 cursor-pointer appearance-none pr-6 outline-none"
                        value={metadata.fileName}
                        onChange={(e) => onFileSelect(e.target.value)}
                    >
                        {fileList && fileList.length > 0 ? (
                             fileList.map((f) => (
                                <option key={f.fileName} value={f.fileName}>
                                    {f.fileName}
                                </option>
                            ))
                        ) : (
                            <option value={metadata.fileName}>{metadata.fileName}</option>
                        )}
                    </select>
                </div>
             </div>
          </div>
        </div>

        <div className="flex gap-2">
            <button 
            onClick={onReset}
            className="px-4 py-2 bg-white border border-slate-300 rounded-md text-sm font-medium text-slate-700 hover:bg-slate-50 hover:text-red-600 transition-colors"
            >
            새 파일 불러오기
            </button>
        </div>
      </div>

      {/* 탭 네비게이션 */}
      <div className="border-b border-slate-200 mb-6 overflow-x-auto">
          <nav className="-mb-px flex space-x-8">
            <button onClick={() => setActiveTab('OVERVIEW')} className={`${activeTab === 'OVERVIEW' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500'} whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm flex items-center gap-2 transition-all`}>
              <Gauge className="w-4 h-4" /> 주행 대시보드
            </button>
            <button onClick={() => setActiveTab('DETAILS')} className={`${activeTab === 'DETAILS' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500'} whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm flex items-center gap-2 transition-all`}>
              <Settings className="w-4 h-4" /> 세션 정보
            </button>
            <button onClick={() => setActiveTab('LOGS')} className={`${activeTab === 'LOGS' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500'} whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm flex items-center gap-2 transition-all`}>
              <BarChart2 className="w-4 h-4" /> 상세 로그
            </button>
            <button onClick={() => setActiveTab('TIMELINE')} className={`${activeTab === 'TIMELINE' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500'} whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm flex items-center gap-2 transition-all`}>
              <History className="w-4 h-4" /> 타임라인
            </button>
            <button onClick={() => setActiveTab('BILLING')} className={`${activeTab === 'BILLING' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500'} whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm flex items-center gap-2 transition-all`}>
              <CreditCard className="w-4 h-4" /> 결제 로그
            </button>
          </nav>
      </div>

      <div className="space-y-6">
        {activeTab === 'OVERVIEW' && (
            <>
                {obdSeries.length > 0 || (diagnosis.detectedDtcs && diagnosis.detectedDtcs.length > 0) ? (
                    <ObdDashboard series={obdSeries} metrics={metrics} detectedDtcs={diagnosis.detectedDtcs} />
                ) : (
                    <div className="bg-white p-12 text-center rounded-2xl border border-dashed border-slate-300">
                        <Gauge className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                        <h3 className="text-slate-900 font-bold text-lg">데이터 없음</h3>
                        <p className="text-slate-500 text-sm mt-2">이 로그 파일에는 분석 가능한 OBD 데이터나 고장 코드가 포함되어 있지 않습니다.</p>
                    </div>
                )}
            </>
        )}
        {activeTab === 'DETAILS' && <SessionInfo metadata={metadata} />}
        {activeTab === 'LOGS' && <LogTable logs={logs} />}
        {activeTab === 'TIMELINE' && <EventTimeline events={lifecycleEvents} />}
        {activeTab === 'BILLING' && <BillingList entries={billingLogs} profiles={purchasedProfiles} orderIds={orderIds} />}
      </div>
    </div>
  );
};

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { ObdDataPoint, ObdMetric, DtcInfo } from '../types';
import { 
  XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, ReferenceLine, AreaChart, Area
} from 'recharts';
import { 
  Play, Pause, RotateCcw, Activity, Zap, Thermometer, 
  Gauge, Wind, Map, Target, Navigation, 
  Clock, AlertTriangle, TrendingUp, Droplets,
  CloudRain, Battery, Timer, Fuel, Stethoscope, Search, ShieldAlert
} from 'lucide-react';
import { detectSegments, calculateTripStats } from '../services/obdParser';

export interface ObdDashboardProps {
  series: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
  detectedDtcs?: DtcInfo[];
}

const StatCard = ({ label, value, unit, icon: Icon, color }: any) => (
  <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex flex-col gap-2 transition-all hover:scale-[1.02]">
    <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${color}`}>
      <Icon className="w-4 h-4" />
    </div>
    <div>
      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">{label}</p>
      <p className="text-xl font-black text-slate-800">
        {value} <span className="text-xs font-bold text-slate-400">{unit}</span>
      </p>
    </div>
  </div>
);

// Explicitly define DtcRow as React.FC to handle the 'key' prop in map iterations correctly
const DtcRow: React.FC<{ dtc: DtcInfo }> = ({ dtc }) => (
  <div className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-xl hover:bg-slate-50 transition-colors">
    <div className="flex items-center gap-3">
      <div className={`w-10 h-10 rounded-lg flex items-center justify-center font-black text-sm ${
        dtc.type === 'P' ? 'bg-red-50 text-red-600' :
        dtc.type === 'U' ? 'bg-amber-50 text-amber-600' :
        'bg-slate-100 text-slate-600'
      }`}>
        {dtc.code}
      </div>
      <div>
        <div className="flex items-center gap-2">
          <span className="text-xs font-bold text-slate-800 uppercase">{dtc.type} Code</span>
          <span className={`text-[10px] px-1.5 py-0.5 rounded font-black uppercase ${
            dtc.status === 'Confirmed' ? 'bg-red-100 text-red-700' :
            dtc.status === 'Pending' ? 'bg-amber-100 text-amber-700' :
            'bg-slate-100 text-slate-500'
          }`}>
            {dtc.status}
          </span>
        </div>
        <p className="text-[11px] text-slate-500 font-mono">Raw: {dtc.rawHex}</p>
      </div>
    </div>
    <button onClick={() => window.open(`https://www.google.com/search?q=OBD2+DTC+${dtc.code}`, '_blank')} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">
      <Search className="w-4 h-4" />
    </button>
  </div>
);

const MetricCard: React.FC<any> = ({ name, value, unit, isAvailable, isSelected, icon, onClick }) => (
  <div 
    onClick={isAvailable ? onClick : undefined}
    className={`bg-white p-4 rounded-xl border-2 transition-all hover:shadow-md flex items-center justify-between group ${
      isSelected ? 'border-indigo-500 shadow-indigo-100 ring-2 ring-indigo-50' : 'border-slate-200'
    } ${isAvailable ? 'cursor-pointer' : 'opacity-40 grayscale cursor-not-allowed'}`}
  >
    <div className="flex items-center gap-4">
      <div className={`p-2.5 rounded-lg transition-colors ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400 group-hover:bg-slate-100'}`}>
        {icon}
      </div>
      <div className="flex flex-col">
        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">{name}</span>
        <div className="flex items-baseline gap-1">
          <span className="text-xl font-black text-slate-800">{isAvailable ? value : '--'}</span>
          <span className="text-[10px] font-bold text-slate-400 uppercase">{unit}</span>
        </div>
      </div>
    </div>
  </div>
);

export const ObdDashboard: React.FC<ObdDashboardProps> = ({ series, metrics, detectedDtcs = [] }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [currentTime, setCurrentTime] = useState(0); 
  const [selectedPids, setSelectedPids] = useState<Set<string>>(new Set(['0C', '0D']));
  const [activeSegmentId, setActiveSegmentId] = useState<number>(0); 
  const [isFollowMode, setIsFollowMode] = useState(true);
  const [viewWindowMs, setViewWindowMs] = useState(120000);

  const requestRef = useRef<number>();
  const lastUpdateRef = useRef<number>();

  const segments = useMemo(() => detectSegments(series), [series]);

  const activeSeries = useMemo(() => {
    if (activeSegmentId === 0) return series;
    return segments.find(s => s.id === activeSegmentId)?.dataPoints || [];
  }, [activeSegmentId, series, segments]);

  const tripStats = useMemo(() => calculateTripStats(activeSeries), [activeSeries]);

  const startTime = activeSeries[0]?.unix || 0;
  const endTime = activeSeries[activeSeries.length - 1]?.unix || 0;
  const totalDuration = endTime - startTime;

  const animate = (time: number) => {
    if (lastUpdateRef.current !== undefined) {
      const deltaTime = time - lastUpdateRef.current;
      setCurrentTime(prev => {
        const next = prev + deltaTime * playbackSpeed;
        if (next >= totalDuration) {
          setIsPlaying(false);
          return totalDuration;
        }
        return next;
      });
    }
    lastUpdateRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (isPlaying) {
      requestRef.current = requestAnimationFrame(animate);
    } else {
      lastUpdateRef.current = undefined;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, playbackSpeed]);

  const currentValues = useMemo(() => {
    const currentUnix = startTime + currentTime;
    const latest: Record<string, number> = {};
    activeSeries.forEach((p) => {
      if (p.unix <= currentUnix) {
        latest[p.pid] = p.value;
      }
    });
    return latest;
  }, [currentTime, activeSeries, startTime]);

  const chartData = useMemo(() => {
    const dataBySec: Record<number, any> = {};
    activeSeries.forEach((p) => {
      const sec = Math.floor((p.unix - startTime) / 1000) * 1000;
      if (!dataBySec[sec]) {
        dataBySec[sec] = { t: sec, timeLabel: formatSimTime(sec) };
      }
      dataBySec[sec][p.pid] = p.value;
    });
    const sorted = Object.values(dataBySec).sort((a: any, b: any) => a.t - b.t);
    if (!isFollowMode) return sorted;
    const halfWindow = viewWindowMs / 2;
    const minT = Math.max(0, currentTime - halfWindow);
    const maxT = minT + viewWindowMs;
    return sorted.filter((d: any) => d.t >= minT && d.t <= maxT);
  }, [activeSeries, startTime, isFollowMode, currentTime, viewWindowMs]);

  const togglePid = (pid: string) => {
    setSelectedPids(prev => {
      const next = new Set(prev);
      if (next.has(pid)) next.delete(pid);
      else next.add(pid);
      return next;
    });
  };

  function formatSimTime(ms: number) {
    const totalSeconds = Math.floor(ms / 1000);
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }

  const getIcon = (pid: string) => {
    switch(pid) {
      case '0C': return <Activity className="w-5 h-5" />;
      case '0D': return <Zap className="w-5 h-5" />;
      case '05': 
      case '0F': 
      case '46':
      case '5C': return <Thermometer className="w-5 h-5" />;
      case '04': 
      case '43': return <Gauge className="w-5 h-5" />;
      case '0A':
      case '0B':
      case '23':
      case '33': return <CloudRain className="w-5 h-5" />;
      case '42': return <Battery className="w-5 h-5" />;
      case '1F': return <Timer className="w-5 h-5" />;
      case '2F':
      case '52': return <Fuel className="w-5 h-5" />;
      default: return <Wind className="w-5 h-5" />;
    }
  };

  const colors = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#3b82f6', '#8b5cf6', '#ec4899', '#14b8a6'];

  return (
    <div className="space-y-6 pb-12 animate-in fade-in duration-500">

      {/* 주행 요약 통계 */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-7 gap-4">
        <StatCard label="주행 거리" value={tripStats.totalDistanceKm} unit="km" icon={Navigation} color="bg-blue-100 text-blue-600" />
        <StatCard label="평균 속도" value={tripStats.averageSpeedKmh} unit="km/h" icon={TrendingUp} color="bg-emerald-100 text-emerald-600" />
        <StatCard label="최고 RPM" value={tripStats.maxRpm} unit="rpm" icon={Activity} color="bg-amber-100 text-amber-600" />
        <StatCard label="공회전 시간" value={formatSimTime(tripStats.idleDurationMs)} unit="" icon={Clock} color="bg-slate-100 text-slate-600" />
        <StatCard label="급감속/가속" value={`${tripStats.hardBrakingCount}/${tripStats.rapidAccelerationCount}`} unit="회" icon={AlertTriangle} color="bg-red-100 text-red-600" />
        <StatCard label="고장 코드" value={detectedDtcs.length} unit="개" icon={Stethoscope} color={detectedDtcs.length > 0 ? "bg-red-600 text-white animate-pulse" : "bg-green-100 text-green-600"} />
        <StatCard label="추정 연비" value={tripStats.estimatedFuelEconomy || '--'} unit="km/L" icon={Droplets} color="bg-indigo-100 text-indigo-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Diagnostic Section */}
        <div className="lg:col-span-1 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
             <div className="flex items-center justify-between mb-4">
               <h3 className="font-bold text-slate-900 flex items-center gap-2">
                 <Stethoscope className="w-5 h-5 text-indigo-600" /> 차량 진단 결과
               </h3>
               {detectedDtcs.length > 0 && <ShieldAlert className="w-5 h-5 text-red-500" />}
             </div>

             <div className="space-y-3 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                {detectedDtcs.length > 0 ? (
                  detectedDtcs.map((dtc, idx) => (
                    <DtcRow key={`${dtc.code}-${idx}`} dtc={dtc} />
                  ))
                ) : (
                  <div className="py-12 text-center flex flex-col items-center gap-3">
                    <div className="w-12 h-12 bg-green-50 rounded-full flex items-center justify-center">
                       <Zap className="w-6 h-6 text-green-500" />
                    </div>
                    <p className="text-sm font-bold text-slate-800">발견된 고장 코드가 없습니다.</p>
                    <p className="text-[10px] text-slate-400">ECU가 모든 시스템을 정상으로 보고하고 있습니다.</p>
                  </div>
                )}
             </div>
          </div>

          {/* Trip Selector */}
          <div className="bg-slate-900 p-6 rounded-2xl shadow-xl border border-slate-800">
             <h3 className="text-white font-bold text-sm mb-4 flex items-center gap-2 uppercase tracking-widest opacity-50">
               <Map className="w-4 h-4" /> Trip Segments
             </h3>
             <div className="space-y-2">
                <button onClick={() => { setActiveSegmentId(0); setCurrentTime(0); }} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-sm font-bold transition-all border ${activeSegmentId === 0 ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-slate-800 text-slate-400 border-slate-700 hover:bg-slate-750'}`}>
                  전체 주행 기록 <span>{formatSimTime(totalDuration)}</span>
                </button>
                {segments.map(seg => (
                  <button key={seg.id} onClick={() => { setActiveSegmentId(seg.id); setCurrentTime(0); }} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-sm font-bold transition-all border ${activeSegmentId === seg.id ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' : 'bg-slate-800 text-slate-400 border-slate-700 hover:bg-slate-750'}`}>
                    Trip {seg.id} <span className="text-[10px] opacity-60">{seg.startLabel} ~ {seg.endLabel}</span>
                  </button>
                ))}
             </div>
          </div>
        </div>

        {/* Playback & Main Chart */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-slate-900 p-6 rounded-2xl shadow-xl border border-slate-800 flex flex-col gap-6">
            <div className="flex flex-col md:flex-row items-center gap-6">
              <div className="flex items-center gap-3">
                <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 flex items-center justify-center bg-indigo-600 hover:bg-indigo-500 text-white rounded-full transition-all shadow-lg">
                  {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                </button>
                <button onClick={() => { setIsPlaying(false); setCurrentTime(0); }} className="w-10 h-10 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-full transition-all">
                  <RotateCcw className="w-5 h-5" />
                </button>
              </div>
              <div className="flex-1 w-full space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase tracking-widest">
                  <span>재생 위치: {formatSimTime(currentTime)}</span>
                  <span>트립 시간: {formatSimTime(totalDuration)}</span>
                </div>
                <input type="range" min={0} max={totalDuration} value={currentTime} onChange={(e) => setCurrentTime(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500" />
              </div>
              <div className="flex items-center bg-slate-800 p-1 rounded-lg">
                {[1, 4, 16, 32].map(speed => (
                  <button key={speed} onClick={() => setPlaybackSpeed(speed)} className={`px-3 py-1 rounded text-xs font-bold transition-all ${playbackSpeed === speed ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}>
                    {speed}x
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {['0C', '0D', '04', '05'].map(pid => {
                const m = metrics[pid];
                if (!m || !m.isAvailable) return null;
                return (
                  <div key={pid} className="bg-slate-800 p-3 rounded-xl border border-slate-700 flex flex-col">
                    <span className="text-[10px] font-bold text-slate-500 uppercase">{m.name}</span>
                    <span className="text-lg font-black text-white">{currentValues[pid] !== undefined ? currentValues[pid] : '--'} <span className="text-[10px] opacity-40">{m.unit}</span></span>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
              <div className="flex items-center gap-4">
                <h3 className="font-bold text-slate-900 flex items-center gap-2 shrink-0">
                  <Activity className="w-5 h-5 text-indigo-600" /> 주행 데이터 정밀 분석
                </h3>
                <div className="flex items-center bg-slate-100 p-1 rounded-lg border border-slate-200">
                  <button onClick={() => setIsFollowMode(!isFollowMode)} className={`flex items-center gap-1.5 px-3 py-1 rounded text-xs font-bold transition-all ${isFollowMode ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>
                    <Target className="w-3.5 h-3.5" /> 추적 모드
                  </button>
                  <div className="w-px h-4 bg-slate-200 mx-1" />
                  <select className="bg-transparent border-none text-[11px] font-bold text-slate-500 focus:ring-0 outline-none cursor-pointer" value={viewWindowMs} onChange={(e) => setViewWindowMs(Number(e.target.value))}>
                    <option value={30000}>30초 뷰</option>
                    <option value={60000}>1분 뷰</option>
                    <option value={120000}>2분 뷰</option>
                    <option value={300000}>5분 뷰</option>
                  </select>
                </div>
              </div>
              <div className="flex flex-wrap gap-2">
                {[...selectedPids].map((pid: string, idx: number) => (
                  <div key={pid} className="flex items-center gap-1.5 px-2 py-1 bg-slate-50 border border-slate-200 rounded text-[10px] font-bold text-slate-600 shadow-sm">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: colors[idx % colors.length] }} />
                    {metrics[pid]?.name}
                  </div>
                ))}
              </div>
            </div>
            <div className="h-[350px]">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData} margin={{ top: 10, right: 30, left: 20, bottom: 10 }}>
                  <defs>
                    {colors.map((color, idx) => (
                      <linearGradient key={idx} id={`color${idx}`} x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor={color} stopOpacity={0.3}/>
                        <stop offset="95%" stopColor={color} stopOpacity={0}/>
                      </linearGradient>
                    ))}
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="t" fontSize={10} tickFormatter={(val) => formatSimTime(val)} axisLine={false} tickLine={false} />
                  <YAxis fontSize={10} axisLine={false} tickLine={false} />
                  <Tooltip labelFormatter={(val) => `Time: ${formatSimTime(Number(val))}`} contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff', fontSize: '12px' }} itemStyle={{ padding: '2px 0' }} />
                  <Legend verticalAlign="top" height={36}/>
                  {[...selectedPids].map((pid: string, idx: number) => (
                    <Area key={pid} type="monotone" dataKey={pid} name={metrics[pid]?.name} stroke={colors[idx % colors.length]} fillOpacity={1} fill={`url(#color${idx % colors.length})`} strokeWidth={2} dot={false} isAnimationActive={false} />
                  ))}
                  <ReferenceLine x={currentTime} stroke="#ef4444" strokeWidth={2} strokeDasharray="5 5" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {(Object.values(metrics) as ObdMetric[]).filter(m => m.isAvailable).map((m: ObdMetric) => (
          <MetricCard 
            key={m.id}
            name={m.name}
            value={currentValues[m.id] !== undefined ? currentValues[m.id] : '--'}
            unit={m.unit}
            isAvailable={m.isAvailable}
            isSelected={selectedPids.has(m.id)}
            icon={getIcon(m.id)}
            onClick={() => togglePid(m.id)}
          />
        ))}
      </div>
    </div>
  );
};
